window.SRVPLUS = window.SRVPLUS || {}; SRVPLUS.questions = SRVPLUS.questions || [];
SRVPLUS.questions.push(
  { id:"D3-001", domain:3, obj:"3.1", diff:"easy", q:"A sysadmin must protect data on server drives so that if a drive is physically stolen while the server is powered off, the contents remain unreadable. Which approach best meets this goal?", options:["Setting restrictive NTFS permissions on the data folders","Enabling a host-based firewall on the server","Full drive encryption such as BitLocker or LUKS","Storing the drives in a locked server rack"], answer:2, explain:"<strong>Full drive encryption such as BitLocker or LUKS</strong> encrypts the entire drive during shutdown and decrypts it at startup, so a stolen powered-off drive stays unreadable without the key.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Setting restrictive NTFS permissions on the data folders</b>: permissions can be bypassed by mounting the drive in another system, so they do not protect a stolen drive.</span><span class='qd'><b>Enabling a host-based firewall on the server</b>: firewalls filter network traffic and do nothing for data at rest on a stolen drive.</span><span class='qd'><b>Storing the drives in a locked server rack</b>: a lock is a deterrent but does not encrypt data, and the scenario assumes the drive was already taken.</span>" },
  { id:"D3-002", domain:3, obj:"3.1", diff:"medium", q:"An organization needs to confirm that a configuration file stored on a Linux server has not been altered since last week. Which technique most directly supports this integrity goal?", options:["Encrypting the file with GnuPG for confidentiality","Applying full drive encryption with LUKS","Moving the file to an off-site cloud location","Generating and comparing a hash with md5sum"], answer:3, explain:"<strong>Generating and comparing a hash with md5sum</strong> lets you compare a current checksum to a prior one; if they differ, the file changed, which is the integrity goal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypting the file with GnuPG for confidentiality</b>: that addresses secrecy, not detecting unexpected changes.</span><span class='qd'><b>Applying full drive encryption with LUKS</b>: drive encryption protects data at rest but does not verify a single file is unchanged.</span><span class='qd'><b>Moving the file to an off-site cloud location</b>: relocating data does not reveal whether the file was modified.</span>" },
  { id:"D3-003", domain:3, obj:"3.1", diff:"medium", q:"A company encrypts all outbound email so recipients can prove who sent each message and the sender cannot later deny sending it. Which goal of encryption does this primarily achieve?", options:["Confidentiality","Non-repudiation","Availability","Scalability"], answer:1, explain:"<strong>Non-repudiation</strong> ensures a sender cannot deny an action; signing with a private key tied only to that sender proves origin.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Confidentiality</b>: that keeps content secret, which is not what proving the sender accomplishes.</span><span class='qd'><b>Availability</b>: availability concerns uptime and access, not proof of origin.</span><span class='qd'><b>Scalability</b>: scalability is a performance concept unrelated to the goals of encryption.</span>" },
  { id:"D3-004", domain:3, obj:"3.1", diff:"hard", q:"A sysadmin must encrypt individual files so they are protected even while the server is powered on and running. Which solution fits this requirement?", options:["Microsoft Encrypting File System (EFS)","BitLocker full volume encryption","A BIOS/UEFI power-on password","NTFS share permissions"], answer:0, explain:"<strong>Microsoft Encrypting File System (EFS)</strong> encrypts individual files, decrypting them when opened and re-encrypting them when closed, protecting data while the system is powered on.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>BitLocker full volume encryption</b>: drive encryption protects a powered-off system, but the volume is decrypted and accessible once the OS is running.</span><span class='qd'><b>A BIOS/UEFI power-on password</b>: that controls boot access, not file-level encryption.</span><span class='qd'><b>NTFS share permissions</b>: permissions restrict access but do not encrypt file contents.</span>" },
  { id:"D3-005", domain:3, obj:"3.1", diff:"easy", q:"Which protocol should a sysadmin use to encrypt a remote command-line administration session to a Linux server?", options:["FTP","Telnet","SSH","HTTP"], answer:2, explain:"<strong>SSH</strong> encrypts remote command-line administration sessions, protecting credentials and commands in transit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>FTP</b>: standard FTP transfers files in cleartext and is not for encrypted shell access.</span><span class='qd'><b>Telnet</b>: Telnet sends the entire session, including passwords, in cleartext.</span><span class='qd'><b>HTTP</b>: HTTP is unencrypted web traffic, not remote administration.</span>" },
  { id:"D3-006", domain:3, obj:"3.1", diff:"medium", q:"A retention policy states customer records must be kept for exactly seven years and then deleted. What is the primary business reason to delete data once it expires rather than keeping it indefinitely?", options:["Indefinite retention improves data integrity","Deleting old data is required to enable encryption","Old data automatically violates the CIA triad","Keeping data longer than required adds storage and management cost without business value"], answer:3, explain:"<strong>Keeping data longer than required adds storage and management cost without business value</strong>, so retention policies dispose of data once it is no longer needed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Indefinite retention improves data integrity</b>: retention duration does not improve integrity.</span><span class='qd'><b>Deleting old data is required to enable encryption</b>: encryption does not depend on deleting expired records.</span><span class='qd'><b>Old data automatically violates the CIA triad</b>: aging data does not inherently violate confidentiality, integrity, or availability.</span>" },
  { id:"D3-007", domain:3, obj:"3.1", diff:"medium", q:"A regulated firm must keep all of its data on-premises and cannot use cloud storage. Which statement best describes the security trade-off of on-site storage?", options:["The business gives up control but gains shared security responsibility","On-site storage automatically encrypts all data at rest","The business retains full control, but in-house staff bear full responsibility for security","On-site storage removes the need for a retention policy"], answer:2, explain:"<strong>The business retains full control, but in-house staff bear full responsibility for security</strong>, which is the defining trade-off of on-site storage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The business gives up control but gains shared security responsibility</b>: that describes off-site or cloud storage, not on-site.</span><span class='qd'><b>On-site storage automatically encrypts all data at rest</b>: encryption must be deliberately enabled regardless of location.</span><span class='qd'><b>On-site storage removes the need for a retention policy</b>: retention policies still apply wherever data lives.</span>" },
  { id:"D3-008", domain:3, obj:"3.1", diff:"easy", q:"Management is worried about employees copying sensitive files onto USB flash drives from a server. A sysadmin disables the USB ports in the BIOS. What additional step prevents someone from simply re-enabling them?", options:["Encrypt the server's network traffic with HTTPS","Enable NIC teaming","Configure a BIOS/UEFI password","Apply a differential backup schedule"], answer:2, explain:"<strong>Configure a BIOS/UEFI password</strong> so an unauthorized user cannot enter firmware settings and re-enable the disabled USB ports.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypt the server's network traffic with HTTPS</b>: that protects data in transit, not BIOS settings.</span><span class='qd'><b>Enable NIC teaming</b>: teaming provides network redundancy, unrelated to USB port control.</span><span class='qd'><b>Apply a differential backup schedule</b>: backups protect against data loss but do not lock firmware settings.</span>" },
  { id:"D3-009", domain:3, obj:"3.1", diff:"hard", q:"A sysadmin wants to encrypt data in transit for a Windows remote desktop administration session. Which protocol provides this encryption?", options:["RDP","SMB","FTP","SNMP"], answer:0, explain:"<strong>RDP</strong> encrypts the remote desktop connection used for administering Windows servers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SMB</b>: SMB is for accessing shared folders, not remote desktop sessions.</span><span class='qd'><b>FTP</b>: FTP transfers files in cleartext and is not a remote desktop protocol.</span><span class='qd'><b>SNMP</b>: SNMP is for network device monitoring and management, not remote desktop.</span>" },
  { id:"D3-010", domain:3, obj:"3.1", diff:"medium", q:"During a legal subpoena, a company must locate electronically stored information (ESI) that may reside on laptops, USB drives, servers, cloud storage, and email. What does this scenario emphasize about data management?", options:["Tracking where data is stored across all locations is critical","Encryption alone satisfies all subpoena requirements","ESI only includes data stored on company servers","Retention policies are unnecessary for legal cases"], answer:0, explain:"<strong>Tracking where data is stored across all locations is critical</strong> because ESI can reside in many places and must be discoverable for legal requests.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encryption alone satisfies all subpoena requirements</b>: encryption protects data but does not locate or produce it.</span><span class='qd'><b>ESI only includes data stored on company servers</b>: ESI spans personal devices, cloud, email, and more.</span><span class='qd'><b>Retention policies are unnecessary for legal cases</b>: retention is often driven precisely by legal and regulatory needs.</span>" },
  { id:"D3-011", domain:3, obj:"3.1", diff:"easy", q:"A company that accepts credit card payments must follow a specific standard governing the security of cardholder data. Which standard applies?", options:["HVAC","RFID","PCI DSS","DMZ"], answer:2, explain:"<strong>PCI DSS</strong> governs information security related to credit card data and applies to organizations that take card payments.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>HVAC</b>: HVAC refers to environmental controls, not data compliance.</span><span class='qd'><b>RFID</b>: RFID is an access-card technology, not a data security standard.</span><span class='qd'><b>DMZ</b>: a DMZ is an isolated network segment, not a compliance standard.</span>" },
  { id:"D3-012", domain:3, obj:"3.1", diff:"medium", q:"A sysadmin needs to protect OS startup settings so an attacker cannot alter how the operating system loads. Which control directly addresses this?", options:["A boot loader password","A round-robin load balancer","A guest network","A synthetic full backup"], answer:0, explain:"<strong>A boot loader password</strong> prevents unauthorized users from changing OS startup settings that could expose data during boot.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A round-robin load balancer</b>: load balancing distributes connections and has nothing to do with boot security.</span><span class='qd'><b>A guest network</b>: a guest network isolates visitor traffic, unrelated to OS startup.</span><span class='qd'><b>A synthetic full backup</b>: backups protect data recovery, not boot settings.</span>" },
  { id:"D3-013", domain:3, obj:"3.1", diff:"hard", q:"A security team is deciding whether to spend on a costly mitigation. The risk is low likelihood and the mitigation is high cost. According to the cost-versus-risk model, what is the most appropriate guidance?", options:["It may not be worth the expense to address","It is worth the expense to address","It must be addressed regardless of cost","It eliminates the risk entirely"], answer:0, explain:"<strong>It may not be worth the expense to address</strong> because a low-likelihood, high-cost risk often does not justify the mitigation spend.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is worth the expense to address</b>: that guidance applies to high-likelihood or low-cost situations, not low/high.</span><span class='qd'><b>It must be addressed regardless of cost</b>: the model balances cost against likelihood rather than mandating action.</span><span class='qd'><b>It eliminates the risk entirely</b>: risks are mitigated, not eliminated, and spending does not guarantee removal.</span>" },
  { id:"D3-014", domain:3, obj:"3.1", diff:"medium", q:"Backup media for a data center is stored in a separate building several miles away. What is the primary security and availability benefit of this practice?", options:["It speeds up nightly backup jobs","It eliminates the need for encryption","It improves network throughput on the LAN","It protects backups from a disaster that strikes the primary site"], answer:3, explain:"<strong>It protects backups from a disaster that strikes the primary site</strong>, preserving data availability if the server room suffers fire or flood.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It speeds up nightly backup jobs</b>: off-site storage does not make backup jobs run faster.</span><span class='qd'><b>It eliminates the need for encryption</b>: off-site media often needs encryption even more, since it leaves the premises.</span><span class='qd'><b>It improves network throughput on the LAN</b>: storage location does not affect LAN throughput.</span>" },
  { id:"D3-015", domain:3, obj:"3.1", diff:"easy", q:"Which of the following is a recognized goal of encryption alongside confidentiality and non-repudiation?", options:["Integrity","Latency","Redundancy","Throughput"], answer:0, explain:"<strong>Integrity</strong> is one of the three goals of encryption, ensuring data has not changed unexpectedly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Latency</b>: latency is a network performance metric, not an encryption goal.</span><span class='qd'><b>Redundancy</b>: redundancy supports availability but is not a goal of encryption.</span><span class='qd'><b>Throughput</b>: throughput measures data rate, not an encryption objective.</span>" },
  { id:"D3-016", domain:3, obj:"3.1", diff:"medium", q:"A sysadmin must protect a database that is in active use 24x7 and cannot have its files closed. Which consideration is most relevant to securing and backing up this data?", options:["Full drive encryption must be disabled","Open file backup capability is required","Permissions cannot be applied to databases","Data in transit cannot be encrypted for databases"], answer:1, explain:"<strong>Open file backup capability is required</strong> because closing the database files would make it inaccessible; special backup programs capture open files.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full drive encryption must be disabled</b>: drive encryption can coexist with a running database and need not be disabled.</span><span class='qd'><b>Permissions cannot be applied to databases</b>: permissions absolutely apply to database files and services.</span><span class='qd'><b>Data in transit cannot be encrypted for databases</b>: database traffic can and should be encrypted in transit.</span>" },
  { id:"D3-017", domain:3, obj:"3.1", diff:"hard", q:"An organization stores data with a cloud provider in a shared storage implementation alongside other tenants. Which concern is most heightened by this arrangement compared to on-site storage?", options:["The data can never be encrypted in the cloud","The cloud eliminates all regulatory obligations","Cloud storage cannot scale to large datasets","The data is stored off-site and possibly co-located with other organizations' data"], answer:3, explain:"<strong>The data is stored off-site and possibly co-located with other organizations' data</strong>, introducing shared-tenancy and reduced-control concerns.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The data can never be encrypted in the cloud</b>: cloud data can be encrypted at rest and in transit.</span><span class='qd'><b>The cloud eliminates all regulatory obligations</b>: regulations still apply and may govern cloud data differently.</span><span class='qd'><b>Cloud storage cannot scale to large datasets</b>: cloud storage is known for easy scalability.</span>" },
  { id:"D3-018", domain:3, obj:"3.1", diff:"medium", q:"A sysadmin runs Get-FileHash in Windows PowerShell on a downloaded installer. What is the most likely purpose?", options:["To encrypt the installer for confidentiality","To compress the installer to save space","To assign NTFS permissions to the installer","To verify the file's integrity has not changed"], answer:3, explain:"<strong>To verify the file's integrity has not changed</strong>, since Get-FileHash returns a hash that can be compared against a known good value.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To encrypt the installer for confidentiality</b>: hashing is one-way and does not encrypt content.</span><span class='qd'><b>To compress the installer to save space</b>: hashing does not change file size or compress data.</span><span class='qd'><b>To assign NTFS permissions to the installer</b>: hashing has nothing to do with setting permissions.</span>" },
  { id:"D3-019", domain:3, obj:"3.1", diff:"easy", q:"Which protocol is commonly used to encrypt web browsing traffic for confidentiality in transit?", options:["SMTP","DHCP","ICMP","HTTPS"], answer:3, explain:"<strong>HTTPS</strong> encrypts web traffic, protecting data confidentiality as it moves between client and server.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SMTP</b>: SMTP is for sending email and is not inherently encrypted web browsing.</span><span class='qd'><b>DHCP</b>: DHCP assigns IP addresses and does not encrypt web traffic.</span><span class='qd'><b>ICMP</b>: ICMP handles diagnostic messages like ping, not encrypted browsing.</span>" },
  { id:"D3-020", domain:3, obj:"3.1", diff:"medium", q:"A company assigns a monetary value to each category of its data. Why is this data value prioritization important for security?", options:["It guarantees the data will never be breached","It gives the organization an incentive to dedicate security resources to high-value data","It replaces the need for backups","It automatically encrypts the most valuable data"], answer:1, explain:"<strong>It gives the organization an incentive to dedicate security resources to high-value data</strong>, because you protect what you recognize as valuable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It guarantees the data will never be breached</b>: valuation does not guarantee immunity from breaches.</span><span class='qd'><b>It replaces the need for backups</b>: knowing value does not back up data.</span><span class='qd'><b>It automatically encrypts the most valuable data</b>: valuation informs decisions but does not perform encryption.</span>" },
  { id:"D3-021", domain:3, obj:"3.2", diff:"easy", q:"A data center installs sturdy steel posts in front of the building entrance to stop vehicles from ramming into it. What are these called?", options:["Turnstiles","Mantraps","Bollards","Patch panels"], answer:2, explain:"<strong>Bollards</strong> enforce a buffer zone between buildings and motor traffic and help prevent ramming attacks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Turnstiles</b>: turnstiles control pedestrian entry one at a time, not vehicles.</span><span class='qd'><b>Mantraps</b>: a mantrap uses two doors to authenticate people, not block vehicles.</span><span class='qd'><b>Patch panels</b>: patch panels organize network cabling in closets.</span>" },
  { id:"D3-022", domain:3, obj:"3.2", diff:"medium", q:"A secure facility installs two interlocking doors where a person enters the first door, authenticates, and only then can pass through the second door. Security can stop the person at any point. What is this control?", options:["A turnstile","A bollard","An access control vestibule (mantrap)","A network closet"], answer:2, explain:"<strong>An access control vestibule (mantrap)</strong> uses two doors with authentication between them, allowing security to stop an individual mid-entry.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A turnstile</b>: a turnstile passes one person at a time but lacks the two-door authentication trap design.</span><span class='qd'><b>A bollard</b>: a bollard blocks vehicles, not people moving through doors.</span><span class='qd'><b>A network closet</b>: a network closet houses devices and is not an entry control.</span>" },
  { id:"D3-023", domain:3, obj:"3.2", diff:"medium", q:"A server room uses a fire suppression system that releases inert gas to reduce oxygen and smother flames. Why is this preferred over water sprinklers in a server room?", options:["Water is cheaper but slower to deploy","Water sprinklers cannot reach rack-mounted servers","Inert gas is non-corrosive and non-conductive, protecting equipment","Inert gas raises oxygen levels for personnel safety"], answer:2, explain:"<strong>Inert gas is non-corrosive and non-conductive, protecting equipment</strong>, whereas water would damage the servers it sprays.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Water is cheaper but slower to deploy</b>: cost and speed are not the reason; equipment damage is.</span><span class='qd'><b>Water sprinklers cannot reach rack-mounted servers</b>: sprinklers can reach racks but would harm them.</span><span class='qd'><b>Inert gas raises oxygen levels for personnel safety</b>: inert gas lowers oxygen to 10-15%, it does not raise it.</span>" },
  { id:"D3-024", domain:3, obj:"3.2", diff:"hard", q:"An HVAC technician sets the data center target temperature. Which range aligns with the recommended target server room temperature?", options:["32-40 degrees Fahrenheit","82-90 degrees Fahrenheit","100-110 degrees Fahrenheit","68-71 degrees Fahrenheit"], answer:3, explain:"<strong>68-71 degrees Fahrenheit</strong> is the recommended target temperature range for a server room.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>32-40 degrees Fahrenheit</b>: that is far too cold and risks condensation and equipment issues.</span><span class='qd'><b>82-90 degrees Fahrenheit</b>: 82 is the upper edge of the maximum range, not the target, and 90 exceeds it.</span><span class='qd'><b>100-110 degrees Fahrenheit</b>: that grossly exceeds safe operating temperatures and would cause overheating.</span>" },
  { id:"D3-025", domain:3, obj:"3.2", diff:"medium", q:"A server room maintains humidity at 40-60% relative humidity. What is the primary reason for controlling humidity at this level?", options:["To reduce static electricity buildup","To increase airflow speed","To lower power consumption","To deter unauthorized access"], answer:0, explain:"<strong>To reduce static electricity buildup</strong>, since proper humidity levels limit static discharge that can damage equipment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To increase airflow speed</b>: humidity does not control airflow speed; aisle layout and fans do.</span><span class='qd'><b>To lower power consumption</b>: humidity control is about static and equipment health, not power savings.</span><span class='qd'><b>To deter unauthorized access</b>: humidity has nothing to do with physical access control.</span>" },
  { id:"D3-026", domain:3, obj:"3.2", diff:"easy", q:"A sysadmin secures rack-mounted servers by locking the rack doors. What threat does locking the rack most directly mitigate?", options:["Unauthorized physical access to USB ports and removable drives","Network eavesdropping on the LAN","Malware infection from email attachments","Excessive heat from poor airflow"], answer:0, explain:"<strong>Unauthorized physical access to USB ports and removable drives</strong> is mitigated by locking the rack, preventing tampering and drive removal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Network eavesdropping on the LAN</b>: that is a network threat addressed by encryption and segmentation.</span><span class='qd'><b>Malware infection from email attachments</b>: anti-malware, not rack locks, addresses that.</span><span class='qd'><b>Excessive heat from poor airflow</b>: HVAC and aisle design manage heat, not locks.</span>" },
  { id:"D3-027", domain:3, obj:"3.2", diff:"medium", q:"A facility designs its data center interior walls to rise from the floor all the way to the structural ceiling rather than stopping at the hanging ceiling. What is the security purpose?", options:["To improve wireless signal coverage","To prevent intruders from climbing over partitions above the drop ceiling","To reduce HVAC costs","To simplify cable routing"], answer:1, explain:"<strong>To prevent intruders from climbing over partitions above the drop ceiling</strong>, since partial walls allow access between sections over the hanging ceiling.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To improve wireless signal coverage</b>: full walls more likely block signals than improve them.</span><span class='qd'><b>To reduce HVAC costs</b>: the goal is access control, not cost reduction.</span><span class='qd'><b>To simplify cable routing</b>: full walls do not simplify cabling and are unrelated to it.</span>" },
  { id:"D3-028", domain:3, obj:"3.2", diff:"hard", q:"A network closet houses switches and routers that are not installed in the main server room. Why is keeping this closet locked important?", options:["The closet maintains the building's humidity","The devices provide direct access to network traffic and contain sensitive configurations","The closet is where backup media is stored long-term","The closet contains the fire suppression controls"], answer:1, explain:"<strong>The devices provide direct access to network traffic and contain sensitive configurations</strong>, so unauthorized access could expose or disrupt the network.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The closet maintains the building's humidity</b>: humidity is an HVAC function, not a network closet role.</span><span class='qd'><b>The closet is where backup media is stored long-term</b>: backups are stored separately, often off-site.</span><span class='qd'><b>The closet contains the fire suppression controls</b>: fire suppression is a separate server room system.</span>" },
  { id:"D3-029", domain:3, obj:"3.2", diff:"medium", q:"Emergency exit doors in a data center building should have which characteristic to maintain physical security?", options:["Be one-way doors with no exterior handles, alarmed and under surveillance","Be propped open for quick egress","Have a shared combination posted nearby","Lead directly into the server room"], answer:0, explain:"<strong>Be one-way doors with no exterior handles, alarmed and under surveillance</strong> so they allow exit but cannot be used to enter, and any use is detected.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Be propped open for quick egress</b>: propping doors open defeats physical security entirely.</span><span class='qd'><b>Have a shared combination posted nearby</b>: posting a combination would let anyone enter.</span><span class='qd'><b>Lead directly into the server room</b>: emergency exits should lead out of the building, not into secure areas.</span>" },
  { id:"D3-030", domain:3, obj:"3.2", diff:"easy", q:"A security desk at the building entrance issues guest badges, requires visitors to sign in and out, and ensures visitors are escorted. What is the primary goal of this security station?", options:["Encrypting network traffic","Backing up the server data","Managing and controlling visitor access","Suppressing fires in the server room"], answer:2, explain:"<strong>Managing and controlling visitor access</strong> is the purpose of a security station that badges, logs, and escorts visitors.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypting network traffic</b>: that is a network security control, not a security desk function.</span><span class='qd'><b>Backing up the server data</b>: backups are unrelated to visitor management.</span><span class='qd'><b>Suppressing fires in the server room</b>: fire suppression is a separate environmental control.</span>" },
  { id:"D3-031", domain:3, obj:"3.2", diff:"medium", q:"A server room uses a lock that identifies users by reading a chipped card containing an authentication certificate. Which lock type is this?", options:["Biometric scanner","Electronic keyless combination lock","Mechanical deadbolt","Card reader"], answer:3, explain:"<strong>Card reader</strong> identifies users by reading chipped cards that contain authentication certificates.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Biometric scanner</b>: a biometric scanner uses physical traits like fingerprints, not cards.</span><span class='qd'><b>Electronic keyless combination lock</b>: that opens for a code or pattern, not a chipped card.</span><span class='qd'><b>Mechanical deadbolt</b>: a deadbolt uses a physical key with no certificate.</span>" },
  { id:"D3-032", domain:3, obj:"3.2", diff:"hard", q:"A high-security data center wants to camouflage the presence of the data center from outsiders. Which architectural choice supports this goal?", options:["Large windows facing the street","Deceptive signage and a lack of windows","Bright exterior signage naming the company","A welcoming open lobby visible from outside"], answer:1, explain:"<strong>Deceptive signage and a lack of windows</strong> helps camouflage the data center and conceal its purpose from outsiders.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Large windows facing the street</b>: windows expose the interior and undermine concealment.</span><span class='qd'><b>Bright exterior signage naming the company</b>: signage advertising the data center defeats camouflage.</span><span class='qd'><b>A welcoming open lobby visible from outside</b>: visibility into the facility works against concealment.</span>" },
  { id:"D3-033", domain:3, obj:"3.2", diff:"medium", q:"An administrator logs into a server by inserting a smart card and then entering a PIN. Which two authentication factors are being combined?", options:["Something you are and somewhere you are","Something you know and something you are","Two instances of something you know","Something you have and something you know"], answer:3, explain:"<strong>Something you have and something you know</strong> combines the smart card (have) with the PIN (know) for multifactor authentication.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Something you are and somewhere you are</b>: no biometric or location factor is used here.</span><span class='qd'><b>Something you know and something you are</b>: no biometric (something you are) factor is present.</span><span class='qd'><b>Two instances of something you know</b>: a smart card is a possession factor, not a knowledge factor.</span>" },
  { id:"D3-034", domain:3, obj:"3.2", diff:"easy", q:"Which physical access control identifies users by reading fingerprints, handprints, or retinal scans?", options:["RFID card","Electronic keyless lock","Biometric scanner","Bollard"], answer:2, explain:"<strong>Biometric scanner</strong> identifies users by physical traits such as fingerprints, handprints, facial recognition, or retinal maps.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RFID card</b>: an RFID card uses a chipped card transmitting a signal, not a body trait.</span><span class='qd'><b>Electronic keyless lock</b>: that opens for a combination or pattern, not biometrics.</span><span class='qd'><b>Bollard</b>: a bollard is a vehicle barrier, not an identification device.</span>" },
  { id:"D3-035", domain:3, obj:"3.2", diff:"medium", q:"A facility installs exterior lighting, cameras, fencing, and landscaping with boulders around the data center building. What security principle does using all of these together represent?", options:["A single point of failure","Layered (defense-in-depth) physical security","Network segmentation","Two-person integrity"], answer:1, explain:"<strong>Layered (defense-in-depth) physical security</strong> uses multiple complementary controls so no single technology must protect everything.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single point of failure</b>: layering is the opposite of relying on one control.</span><span class='qd'><b>Network segmentation</b>: that is a network design concept, not a physical perimeter strategy.</span><span class='qd'><b>Two-person integrity</b>: that requires two people to authorize an action, unrelated to perimeter design.</span>" },
  { id:"D3-036", domain:3, obj:"3.2", diff:"hard", q:"A sysadmin places backup media in a fireproof safe located away from the network operations center. What is the main rationale for the separate location?", options:["To keep media closer to the servers for faster restores","To improve the speed of writing to the media","To reduce the cost of the media","To maintain data availability if a disaster strikes the server room"], answer:3, explain:"<strong>To maintain data availability if a disaster strikes the server room</strong>, separating backup media from servers preserves recoverability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To keep media closer to the servers for faster restores</b>: the goal is separation, not proximity.</span><span class='qd'><b>To improve the speed of writing to the media</b>: location does not affect write speed.</span><span class='qd'><b>To reduce the cost of the media</b>: a fireproof safe is about protection, not cost reduction.</span>" },
  { id:"D3-037", domain:3, obj:"3.2", diff:"medium", q:"A facility uses turnstiles that reach from floor to ceiling at the building entrance. What is the primary function of these turnstiles?", options:["To authenticate users with two doors and a security stop","To block vehicles from approaching the building","To pass individuals through an entry one at a time","To house network switches securely"], answer:2, explain:"<strong>To pass individuals through an entry one at a time</strong> is the function of floor-to-ceiling turnstiles, controlling pedestrian flow.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To authenticate users with two doors and a security stop</b>: that describes a mantrap, not a turnstile.</span><span class='qd'><b>To block vehicles from approaching the building</b>: bollards block vehicles, not turnstiles.</span><span class='qd'><b>To house network switches securely</b>: that is the role of a locked network closet.</span>" },
  { id:"D3-038", domain:3, obj:"3.2", diff:"easy", q:"Why are server rooms typically designed without windows?", options:["To improve wireless signal strength","To reduce physical security exposure and visibility into the room","To lower the relative humidity","To make cable routing easier"], answer:1, explain:"<strong>To reduce physical security exposure and visibility into the room</strong>, since windows would expose equipment and offer a potential entry point.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To improve wireless signal strength</b>: windowless design relates to security, not signal strength.</span><span class='qd'><b>To lower the relative humidity</b>: humidity is controlled by HVAC, not by removing windows.</span><span class='qd'><b>To make cable routing easier</b>: windows have no bearing on cable routing.</span>" },
  { id:"D3-039", domain:3, obj:"3.2", diff:"medium", q:"A data center designs its interior with redundant utilities and multiple electrical circuits. What is the primary goal of this design choice?", options:["To eliminate single points of failure in power","To reduce the server room temperature","To simplify visitor management","To replace the need for a UPS"], answer:0, explain:"<strong>To eliminate single points of failure in power</strong> by providing redundant utilities and circuits so one failure does not halt operations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To reduce the server room temperature</b>: cooling is handled by HVAC, not redundant circuits.</span><span class='qd'><b>To simplify visitor management</b>: power redundancy is unrelated to visitor control.</span><span class='qd'><b>To replace the need for a UPS</b>: redundant circuits complement, not replace, a UPS.</span>" },
  { id:"D3-040", domain:3, obj:"3.2", diff:"hard", q:"A high-security environment requires that users provide a fingerprint scan AND insert an RFID access card to enter the server room. This combination is best described as which control?", options:["Single-factor authentication","Multifactor authentication","A bollard array","A guest network"], answer:1, explain:"<strong>Multifactor authentication</strong> combines two distinct factors here: a biometric (something you are) and an RFID card (something you have).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Single-factor authentication</b>: two different factor types are used, making it multifactor.</span><span class='qd'><b>A bollard array</b>: bollards are vehicle barriers, not authentication.</span><span class='qd'><b>A guest network</b>: a guest network isolates visitor traffic, not a door control.</span>" },
  { id:"D3-041", domain:3, obj:"3.3", diff:"easy", q:"A NAC solution checks that each connecting device has a firewall enabled and antivirus installed before granting network access. A laptop fails the antivirus check. What is a typical NAC response?", options:["Place the device on an isolated network until it is compliant","Grant full network access anyway","Permanently delete the device's data","Disable the NAC service"], answer:0, explain:"<strong>Place the device on an isolated network until it is compliant</strong> is a standard NAC response, either denying access or quarantining the device.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Grant full network access anyway</b>: that defeats the purpose of NAC enforcement.</span><span class='qd'><b>Permanently delete the device's data</b>: NAC controls access; it does not wipe endpoints.</span><span class='qd'><b>Disable the NAC service</b>: disabling NAC would remove the very protection being enforced.</span>" },
  { id:"D3-042", domain:3, obj:"3.3", diff:"medium", q:"An administrator wants to isolate Finance Department traffic from Engineering traffic using switch configuration without relying on routers and physical proximity. Which technology should be used?", options:["DMZ","Air gap","NIC teaming","VLANs"], answer:3, explain:"<strong>VLANs</strong> segment at the switch level using tags, isolating traffic flexibly without router-based physical proximity requirements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DMZ</b>: a DMZ isolates Internet-facing servers, not internal departments by switch port.</span><span class='qd'><b>Air gap</b>: an air gap provides no connectivity at all, which is more extreme than needed.</span><span class='qd'><b>NIC teaming</b>: NIC teaming aggregates adapters for redundancy, not traffic segmentation.</span>" },
  { id:"D3-043", domain:3, obj:"3.3", diff:"medium", q:"A company hosts public DNS, web, and email servers that need direct Internet connectivity but should be isolated from the internal LAN. Where should these servers be placed?", options:["In a demilitarized zone (DMZ)","On the internal production VLAN","On the guest wireless network","Behind a full air gap"], answer:0, explain:"<strong>In a demilitarized zone (DMZ)</strong>, an isolated segment for Internet-facing services that keeps them separate from the trusted internal network.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>On the internal production VLAN</b>: exposing internal segments to the Internet increases risk.</span><span class='qd'><b>On the guest wireless network</b>: the guest network is for visitor devices, not production services.</span><span class='qd'><b>Behind a full air gap</b>: an air gap blocks all connectivity, but these servers need Internet access.</span>" },
  { id:"D3-044", domain:3, obj:"3.3", diff:"hard", q:"A government facility requires that a classified network have no physical path whatsoever to any other network. Which approach achieves this?", options:["An air gap","A VLAN with strict tagging","A stateful firewall at the perimeter","A DMZ"], answer:0, explain:"<strong>An air gap</strong> physically separates the networks so no path exists for traffic to move between them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A VLAN with strict tagging</b>: VLANs still share switching infrastructure and a path exists.</span><span class='qd'><b>A stateful firewall at the perimeter</b>: a firewall filters traffic but still permits a connection path.</span><span class='qd'><b>A DMZ</b>: a DMZ is connected to other networks through controlled paths, not isolated by an air gap.</span>" },
  { id:"D3-045", domain:3, obj:"3.3", diff:"easy", q:"A host-based firewall on a web server is blocking inbound connections on TCP ports 80 and 443, so users cannot reach the internal web app. What should the administrator do?", options:["Disable the antivirus software","Move the server to the DMZ","Open ports 80 and 443 for the web service in the host firewall","Replace the NIC"], answer:2, explain:"<strong>Open ports 80 and 443 for the web service in the host firewall</strong>, since those ports must be permitted for HTTP and HTTPS access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disable the antivirus software</b>: antivirus is unrelated to the blocked web ports.</span><span class='qd'><b>Move the server to the DMZ</b>: relocation does not fix the local firewall rule blocking the ports.</span><span class='qd'><b>Replace the NIC</b>: the NIC is functioning; the firewall rule is the issue.</span>" },
  { id:"D3-046", domain:3, obj:"3.3", diff:"medium", q:"A sysadmin uses Wireshark and notices an internal web app sends login credentials in cleartext. What is the most appropriate mitigation?", options:["Switch the application to use HTTPS (TLS) encryption","Increase the server's RAM","Disable the firewall to speed traffic","Move the server to a different VLAN only"], answer:0, explain:"<strong>Switch the application to use HTTPS (TLS) encryption</strong> so intercepted traffic, including credentials, cannot be read.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increase the server's RAM</b>: memory does not encrypt traffic.</span><span class='qd'><b>Disable the firewall to speed traffic</b>: disabling the firewall reduces security and does not encrypt data.</span><span class='qd'><b>Move the server to a different VLAN only</b>: segmentation alone still leaves credentials in cleartext on that segment.</span>" },
  { id:"D3-047", domain:3, obj:"3.3", diff:"medium", q:"Security hardening guidance recommends that a server run only the services it actually needs. What is the primary security benefit of disabling unnecessary services?", options:["It reduces the server's attack surface","It increases the server's IP address pool","It encrypts all stored data","It enables NIC teaming automatically"], answer:0, explain:"<strong>It reduces the server's attack surface</strong> by removing unneeded functionality that attackers could exploit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It increases the server's IP address pool</b>: disabling services does not change addressing.</span><span class='qd'><b>It encrypts all stored data</b>: hardening services is unrelated to encrypting data at rest.</span><span class='qd'><b>It enables NIC teaming automatically</b>: NIC teaming is a separate configuration.</span>" },
  { id:"D3-048", domain:3, obj:"3.3", diff:"hard", q:"A perimeter firewall between the trusted internal network and the untrusted Internet must track the state of connections to make filtering decisions. Which firewall type is described?", options:["Simple packet filtering firewall","Stateful firewall","Host-based firewall on a single workstation","A network access control (NAC) appliance"], answer:1, explain:"<strong>Stateful firewall</strong> tracks the state of connections and is commonly placed at the perimeter between trusted and untrusted networks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Simple packet filtering firewall</b>: packet filters examine packets individually without tracking connection state.</span><span class='qd'><b>Host-based firewall on a single workstation</b>: that protects one host, not the network perimeter.</span><span class='qd'><b>A network access control (NAC) appliance</b>: NAC enforces device compliance, not stateful traffic filtering at the perimeter.</span>" },
  { id:"D3-049", domain:3, obj:"3.3", diff:"easy", q:"Which secure protocol and port pair is correct for encrypted file transfer over SSH?", options:["SFTP over TCP 22","FTP over TCP 21","HTTP over TCP 80","Telnet over TCP 23"], answer:0, explain:"<strong>SFTP over TCP 22</strong> provides encrypted file transfer using the SSH protocol on port 22.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>FTP over TCP 21</b>: standard FTP on port 21 is unencrypted.</span><span class='qd'><b>HTTP over TCP 80</b>: HTTP on port 80 is unencrypted web traffic, not file transfer.</span><span class='qd'><b>Telnet over TCP 23</b>: Telnet is an unencrypted remote terminal protocol.</span>" },
  { id:"D3-050", domain:3, obj:"3.3", diff:"medium", q:"When configuring permissions, an administrator grants each user only the minimum access required to perform their job. Which security principle is being applied?", options:["Two-person integrity","Defense in depth","Principle of least privilege","Separation of duties"], answer:2, explain:"<strong>Principle of least privilege</strong> grants users as little access as possible while still allowing them to do their jobs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Two-person integrity</b>: that requires two people to perform a sensitive action, a different concept.</span><span class='qd'><b>Defense in depth</b>: that layers multiple controls, not specifically about minimal access.</span><span class='qd'><b>Separation of duties</b>: that divides tasks among people to prevent fraud, distinct from minimal access.</span>" },
  { id:"D3-051", domain:3, obj:"3.3", diff:"hard", q:"A Windows user can open a file when logged on locally at the server but is denied when accessing the same file over the network share. Which is the most likely cause?", options:["The NTFS permissions are correct but the Share permissions are more restrictive","The server's CPU is overloaded","The file is encrypted with EFS","The server is missing a UPS"], answer:0, explain:"<strong>The NTFS permissions are correct but the Share permissions are more restrictive</strong>; network access is governed by the more restrictive of NTFS and Share permissions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The server's CPU is overloaded</b>: CPU load causes slowness, not a permission denial.</span><span class='qd'><b>The file is encrypted with EFS</b>: EFS would block the owner locally too, but local access succeeds.</span><span class='qd'><b>The server is missing a UPS</b>: a UPS relates to power, not file permissions.</span>" },
  { id:"D3-052", domain:3, obj:"3.3", diff:"medium", q:"A sysadmin reviews firewall logs and finds many ports open that no service is using. From a hardening perspective, what should be done?", options:["Open additional ports for redundancy","Disable all firewall logging","Move the firewall behind the web server","Close the unused ports to reduce exposure"], answer:3, explain:"<strong>Close the unused ports to reduce exposure</strong>, since open, unused ports expose the server to unauthorized access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Open additional ports for redundancy</b>: more open ports increase, not reduce, exposure.</span><span class='qd'><b>Disable all firewall logging</b>: logging is needed to detect suspicious activity.</span><span class='qd'><b>Move the firewall behind the web server</b>: relocating it does not address the open ports.</span>" },
  { id:"D3-053", domain:3, obj:"3.3", diff:"easy", q:"An organization wants visitors to have basic Internet and printing access without connecting to the production network. Which solution is most appropriate?", options:["A second domain controller","An isolated guest network","A degaussing station","A synthetic full backup"], answer:1, explain:"<strong>An isolated guest network</strong> provides visitors basic Internet and printing access while keeping them off the production network.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A second domain controller</b>: that adds directory redundancy, not visitor isolation.</span><span class='qd'><b>A degaussing station</b>: degaussing destroys data on media, unrelated to guest access.</span><span class='qd'><b>A synthetic full backup</b>: that is a backup method, not a network isolation control.</span>" },
  { id:"D3-054", domain:3, obj:"3.3", diff:"medium", q:"An administrator finds that an essential server application will not start after a recent change. The Group Policy and permissions look fine, but the required Windows service is set to disabled. What is the corrective action?", options:["Reinstall the operating system","Replace the server's drives","Re-enable and start the required service","Change the server's IP subnet"], answer:2, explain:"<strong>Re-enable and start the required service</strong>, because a disabled essential service limits the server's functionality and prevents the app from running.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reinstall the operating system</b>: that is drastic and unnecessary for a disabled service.</span><span class='qd'><b>Replace the server's drives</b>: the drives are not the cause of a disabled service.</span><span class='qd'><b>Change the server's IP subnet</b>: addressing is unrelated to a stopped service.</span>" },
  { id:"D3-055", domain:3, obj:"3.3", diff:"hard", q:"On a Linux server, the SSH daemon is not running and remote administrators cannot connect. Which command starts the service?", options:["ipconfig /renew","systemctl start sshd","md5sum sshd","degauss sshd"], answer:1, explain:"<strong>systemctl start sshd</strong> starts the SSH daemon on a Linux server using systemd.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ipconfig /renew</b>: that is a Windows networking command, not a Linux service command.</span><span class='qd'><b>md5sum sshd</b>: md5sum generates a file hash, it does not start services.</span><span class='qd'><b>degauss sshd</b>: degaussing applies to magnetic media destruction, not services.</span>" },
  { id:"D3-056", domain:3, obj:"3.3", diff:"medium", q:"A Linux administrator wants to enforce mandatory access controls to ensure processes and users only access the resources they are explicitly permitted. Which tool supports this?", options:["tcpdump","Nmap","SELinux","systemctl"], answer:2, explain:"<strong>SELinux</strong> enforces user and process access controls, helping ensure proper privilege levels and file access on Linux.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>tcpdump</b>: tcpdump captures network packets, it does not enforce access control.</span><span class='qd'><b>Nmap</b>: Nmap scans networks and hosts, not an access control enforcer.</span><span class='qd'><b>systemctl</b>: systemctl manages services, not mandatory access controls.</span>" },
  { id:"D3-057", domain:3, obj:"3.3", diff:"easy", q:"Which tool would an administrator use to verify that a server's firewall and listening services are configured correctly by checking which ports are open?", options:["A degausser","A UPS","A bollard","A port scanner"], answer:3, explain:"<strong>A port scanner</strong> reveals which ports are open, helping verify firewall and service configurations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A degausser</b>: a degausser destroys data on magnetic media.</span><span class='qd'><b>A UPS</b>: a UPS provides backup power, not port analysis.</span><span class='qd'><b>A bollard</b>: a bollard is a physical vehicle barrier.</span>" },
  { id:"D3-058", domain:3, obj:"3.3", diff:"medium", q:"A misconfigured Group Policy setting is preventing anti-malware from running on several Windows servers. Which tool helps an administrator determine the effective applied policy on a server?", options:["tcpdump","Wireshark","ipconfig","gpresult"], answer:3, explain:"<strong>gpresult</strong> reports the resultant set of Group Policy applied to a machine, helping diagnose misconfigured policies.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>tcpdump</b>: tcpdump captures packets, not Group Policy results.</span><span class='qd'><b>Wireshark</b>: Wireshark analyzes network traffic, not policy application.</span><span class='qd'><b>ipconfig</b>: ipconfig shows IP configuration, not Group Policy.</span>" },
  { id:"D3-059", domain:3, obj:"3.3", diff:"hard", q:"Users report they cannot reach a newly published internal site at http and https. The web service is running and Group Policy is correct, but a host-based firewall change was made yesterday. What is the most likely cause?", options:["The site's content was never created","The server's drives were degaussed","The DNS server was decommissioned last year","The host firewall is blocking TCP 80 and 443"], answer:3, explain:"<strong>The host firewall is blocking TCP 80 and 443</strong>, the recent firewall change most likely closed the web ports needed for access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The site's content was never created</b>: the service is running, so content exists; the timing points to the firewall change.</span><span class='qd'><b>The server's drives were degaussed</b>: degaussing would destroy data and take the server down entirely.</span><span class='qd'><b>The DNS server was decommissioned last year</b>: a year-old change would not cause a problem that started today after a firewall edit.</span>" },
  { id:"D3-060", domain:3, obj:"3.3", diff:"medium", q:"An administrator wants to combine confidentiality, integrity, and authentication for network traffic between two sites using a protocol that operates with UDP 500 and UDP 4500. Which protocol is this?", options:["SMB","HTTP","IPsec","Telnet"], answer:2, explain:"<strong>IPsec</strong> encrypts network traffic and commonly uses UDP 500 and UDP 4500 for its negotiation and traversal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SMB</b>: SMB provides file sharing over ports such as 445, not site-to-site encryption on those UDP ports.</span><span class='qd'><b>HTTP</b>: HTTP is unencrypted web traffic on TCP 80.</span><span class='qd'><b>Telnet</b>: Telnet is unencrypted remote terminal access.</span>" },
  { id:"D3-061", domain:3, obj:"3.4", diff:"easy", q:"An organization wants to detect data being exfiltrated and prevent sensitive files from leaving the network. Which technology is specifically designed for this?", options:["A round-robin load balancer","Data Loss Prevention (DLP)","A cold site","A degausser"], answer:1, explain:"<strong>Data Loss Prevention (DLP)</strong> monitors and prevents sensitive data from leaving the organization.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A round-robin load balancer</b>: that distributes connections, not data exfiltration prevention.</span><span class='qd'><b>A cold site</b>: a cold site is a disaster recovery location, not a data leak control.</span><span class='qd'><b>A degausser</b>: a degausser destroys media; it does not monitor data movement.</span>" },
  { id:"D3-062", domain:3, obj:"3.4", diff:"medium", q:"A security team aggregates logs from servers, firewalls, and applications into one platform to correlate events and detect threats. Which solution does this?", options:["NAC","UPS","SIEM","PDU"], answer:2, explain:"<strong>SIEM</strong> collects and correlates log data to detect suspicious activity and support compliance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>NAC</b>: NAC enforces device compliance before network access, not log correlation.</span><span class='qd'><b>UPS</b>: a UPS supplies backup power, unrelated to log analysis.</span><span class='qd'><b>PDU</b>: a PDU distributes power, not security event data.</span>" },
  { id:"D3-063", domain:3, obj:"3.4", diff:"hard", q:"An organization requires that at least two key holders combine their separate keys before any encrypted data can be decrypted. Which mitigation technique is described?", options:["Round-robin scheduling","Split encryption keys with two-person integrity","A synthetic full backup","NIC teaming"], answer:1, explain:"<strong>Split encryption keys with two-person integrity</strong> require two key holders to combine keys, preventing a single person from decrypting data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Round-robin scheduling</b>: that distributes load balancer connections, not key control.</span><span class='qd'><b>A synthetic full backup</b>: that is a backup assembly method, not access control.</span><span class='qd'><b>NIC teaming</b>: NIC teaming aggregates network adapters, unrelated to key splitting.</span>" },
  { id:"D3-064", domain:3, obj:"3.4", diff:"medium", q:"To reduce the risk that one employee can single-handedly steal sensitive data, a company divides sensitive responsibilities among multiple people. Which two strategies best support this goal?", options:["Round robin and weighted scheduling","Hot site and cold site","Separation of roles and role rotation","FIFO and Tower of Hanoi"], answer:2, explain:"<strong>Separation of roles and role rotation</strong> force perpetrators to collude and reduce the chance any one person can misuse access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Round robin and weighted scheduling</b>: those are load balancing methods, not insider-threat controls.</span><span class='qd'><b>Hot site and cold site</b>: those are disaster recovery sites, not role controls.</span><span class='qd'><b>FIFO and Tower of Hanoi</b>: those are backup media rotation schemes.</span>" },
  { id:"D3-065", domain:3, obj:"3.4", diff:"easy", q:"Which category of information is considered PII that must be protected during a breach?", options:["A user's Social Security number","The server's CPU temperature","The data center's relative humidity","The VLAN tag number"], answer:0, explain:"<strong>A user's Social Security number</strong> is personally identifiable information that is a primary target during breaches.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The server's CPU temperature</b>: a hardware metric is not personal information.</span><span class='qd'><b>The data center's relative humidity</b>: an environmental reading is not PII.</span><span class='qd'><b>The VLAN tag number</b>: a network tag does not identify a person.</span>" },
  { id:"D3-066", domain:3, obj:"3.4", diff:"medium", q:"A sysadmin reviews the risks table and sees that log analysis with a SIEM appears as a mitigation for many different risk types. What does this indicate about SIEM-based log analysis?", options:["It is a particularly broadly useful security strategy","It only mitigates hardware failure","It replaces the need for backups","It is only useful for physical security"], answer:0, explain:"<strong>It is a particularly broadly useful security strategy</strong>, since the same mitigation covering many risks signals high value.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It only mitigates hardware failure</b>: SIEM addresses many risks, not just hardware failure.</span><span class='qd'><b>It replaces the need for backups</b>: log analysis does not back up data.</span><span class='qd'><b>It is only useful for physical security</b>: SIEM is primarily a data and network security tool.</span>" },
  { id:"D3-067", domain:3, obj:"3.4", diff:"hard", q:"A scenario uses a single golden key capable of decrypting all data in the environment. What is the main security drawback of relying solely on this golden key?", options:["It cannot decrypt any encrypted data","It only works on unencrypted data","It is a single point of compromise that can unlock everything","It requires two people to function"], answer:2, explain:"<strong>It is a single point of compromise that can unlock everything</strong>, like a master key, so its theft exposes all data; split keys mitigate this.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It cannot decrypt any encrypted data</b>: the golden key is defined as able to decrypt all data.</span><span class='qd'><b>It only works on unencrypted data</b>: it specifically decrypts encrypted data.</span><span class='qd'><b>It requires two people to function</b>: that describes split keys, not a single golden key.</span>" },
  { id:"D3-068", domain:3, obj:"3.4", diff:"medium", q:"An administrator implements data monitoring and SIEM log analysis specifically to address the risk of insider threats. Why are these mitigations well suited to insider threats?", options:["They physically destroy compromised drives","They increase network bandwidth","They detect unusual access and activity patterns by trusted users","They replace the need for permissions"], answer:2, explain:"<strong>They detect unusual access and activity patterns by trusted users</strong>, which is how monitoring and SIEM help catch insider misuse.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They physically destroy compromised drives</b>: monitoring does not destroy media.</span><span class='qd'><b>They increase network bandwidth</b>: detection tools do not add bandwidth.</span><span class='qd'><b>They replace the need for permissions</b>: monitoring complements permissions, it does not replace them.</span>" },
  { id:"D3-069", domain:3, obj:"3.4", diff:"easy", q:"Accidental disclosure of customer PII may constitute a crime or breach of contract. What is the most common motivation for attackers to target PII?", options:["Reducing humidity","Improving uptime","Speeding up backups","Identity theft"], answer:3, explain:"<strong>Identity theft</strong> is a common cybercrime, and PII is a primary target when systems are breached.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reducing humidity</b>: humidity is an environmental concern, not an attacker motive.</span><span class='qd'><b>Improving uptime</b>: attackers stealing PII are not trying to improve availability.</span><span class='qd'><b>Speeding up backups</b>: backup speed is unrelated to PII theft.</span>" },
  { id:"D3-070", domain:3, obj:"3.4", diff:"medium", q:"A regulated organization must demonstrate compliance and be able to investigate incidents after the fact. Which combination of mitigations most directly supports both compliance and investigation across many risk types?", options:["Round robin and weighted load balancing","Log analysis (SIEM), data monitoring, and data retention","Degaussing and shredding","Bollards and turnstiles"], answer:1, explain:"<strong>Log analysis (SIEM), data monitoring, and data retention</strong> support compliance and after-the-fact investigation and appear across many risk types.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Round robin and weighted load balancing</b>: those manage traffic distribution, not compliance investigation.</span><span class='qd'><b>Degaussing and shredding</b>: those are media destruction methods, not investigative controls.</span><span class='qd'><b>Bollards and turnstiles</b>: those are physical perimeter controls, not data investigation tools.</span>" },
  { id:"D3-071", domain:3, obj:"3.4", diff:"hard", q:"A backdoor was discovered allowing unwanted access to a server through social engineering. Which set of mitigations is appropriate for this 'unwanted access' risk?", options:["Increasing the server room temperature","Data monitoring, two-person integrity, regulatory constraints, and data retention","Removing all firewalls","Disabling SIEM logging"], answer:1, explain:"<strong>Data monitoring, two-person integrity, regulatory constraints, and data retention</strong> are the recommended mitigations for unwanted access via backdoor or social engineering.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increasing the server room temperature</b>: temperature change does not address access risk.</span><span class='qd'><b>Removing all firewalls</b>: removing firewalls increases exposure.</span><span class='qd'><b>Disabling SIEM logging</b>: disabling logging removes detection capability.</span>" },
  { id:"D3-072", domain:3, obj:"3.4", diff:"medium", q:"A cloud service provider certifies its services as PCI compliant. Why is this certification useful when an organization that handles credit cards chooses a cloud solution?", options:["The CSP handles that compliance, easing management for the customer","It guarantees the customer can never be audited","It eliminates the need to protect PII","It automatically encrypts the customer's email"], answer:0, explain:"<strong>The CSP handles that compliance, easing management for the customer</strong>, which simplifies meeting PCI requirements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It guarantees the customer can never be audited</b>: certification does not exempt the customer from audits.</span><span class='qd'><b>It eliminates the need to protect PII</b>: organizations still must protect PII.</span><span class='qd'><b>It automatically encrypts the customer's email</b>: PCI certification does not encrypt email.</span>" },
  { id:"D3-073", domain:3, obj:"3.4", diff:"easy", q:"Which mitigation technique relies on at least two entities agreeing before sensitive data can be decrypted, helping prevent a single rogue insider from acting alone?", options:["Round robin scheduling","NIC teaming","Two-person integrity","FIFO rotation"], answer:2, explain:"<strong>Two-person integrity</strong> requires at least two entities to agree before decrypting data, supporting role separation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Round robin scheduling</b>: that is a load balancing method.</span><span class='qd'><b>NIC teaming</b>: that aggregates network adapters for redundancy.</span><span class='qd'><b>FIFO rotation</b>: that is a backup media rotation scheme.</span>" },
  { id:"D3-074", domain:3, obj:"3.4", diff:"medium", q:"A help desk ticket reports a user cannot open files they previously could. Investigation rules out network issues. Which causes are most likely for this file integrity and access problem?", options:["An expired SSL certificate on the website","A round-robin load balancer","A cold disaster recovery site","Misconfigured permissions or malware"], answer:3, explain:"<strong>Misconfigured permissions or malware</strong> commonly cause file access and integrity issues for users.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An expired SSL certificate on the website</b>: that affects HTTPS sites, not local file opening.</span><span class='qd'><b>A round-robin load balancer</b>: load balancing does not block file access.</span><span class='qd'><b>A cold disaster recovery site</b>: a DR site is unrelated to a user opening files.</span>" },
  { id:"D3-075", domain:3, obj:"3.4", diff:"hard", q:"An organization is concerned about unwanted duplication (theft) of proprietary research files. Which mitigation set aligns specifically with this risk?", options:["Increasing relative humidity to 80%","Replacing all switches with hubs","Disabling all backups","Log analysis (SIEM) and two-person integrity"], answer:3, explain:"<strong>Log analysis (SIEM) and two-person integrity</strong> are the mitigations aligned with unwanted duplication or theft of data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increasing relative humidity to 80%</b>: that harms equipment and does nothing for theft.</span><span class='qd'><b>Replacing all switches with hubs</b>: hubs broadcast traffic, increasing eavesdropping risk.</span><span class='qd'><b>Disabling all backups</b>: removing backups increases data loss risk.</span>" },
  { id:"D3-076", domain:3, obj:"3.5", diff:"easy", q:"A company wants the fastest possible restore process even if nightly backups take longer. Which backup scheme best fits this priority?", options:["Full followed by daily incrementals","Full followed by daily differentials","Only snapshots, no full backups","No backups, only replication"], answer:1, explain:"<strong>Full followed by daily differentials</strong> gives faster restores because only two jobs (the full and the latest differential) are needed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full followed by daily incrementals</b>: incrementals restore slower because every job since the full is required.</span><span class='qd'><b>Only snapshots, no full backups</b>: snapshots are point-in-time copies, not a full restore strategy.</span><span class='qd'><b>No backups, only replication</b>: replication propagates errors and is not a substitute for backups.</span>" },
  { id:"D3-077", domain:3, obj:"3.5", diff:"medium", q:"An incremental backup is run nightly after a weekly full. What is a defining behavior of an incremental backup?", options:["It backs up changes since the last backup and resets the archive bit","It backs up changes since the full without resetting the archive bit","It always backs up the entire system","It only captures system state, never user data"], answer:0, explain:"<strong>It backs up changes since the last backup and resets the archive bit</strong>, which makes incrementals fast to create but slower to restore.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It backs up changes since the full without resetting the archive bit</b>: that describes a differential backup.</span><span class='qd'><b>It always backs up the entire system</b>: that describes a full backup.</span><span class='qd'><b>It only captures system state, never user data</b>: incrementals capture changed data, not just system state.</span>" },
  { id:"D3-078", domain:3, obj:"3.5", diff:"hard", q:"A backup product combines the most recent full backup with subsequent incrementals into one aggregated job, without reading the original source data again. What is this called?", options:["A differential backup","A synthetic full backup","A snapshot","A print backup"], answer:1, explain:"<strong>A synthetic full backup</strong> is assembled from an existing full plus its incrementals rather than from the original data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A differential backup</b>: a differential captures changes since the full, not an aggregation of jobs.</span><span class='qd'><b>A snapshot</b>: a snapshot is a point-in-time read-only copy, not a combined job.</span><span class='qd'><b>A print backup</b>: a print backup writes encoded data to paper.</span>" },
  { id:"D3-079", domain:3, obj:"3.5", diff:"medium", q:"An organization needs immediate, automatic takeover of a critical web service if one server fails, with no client reconfiguration. Which high availability approach fits?", options:["A first-in, first-out tape rotation","A failover server cluster sharing a single IP address","A cold disaster recovery site","A paper backup scheme"], answer:1, explain:"<strong>A failover server cluster sharing a single IP address</strong> lets a second node take over automatically with no client changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A first-in, first-out tape rotation</b>: that is a media rotation scheme, not high availability.</span><span class='qd'><b>A cold disaster recovery site</b>: a cold site takes the longest to bring online, not immediate.</span><span class='qd'><b>A paper backup scheme</b>: paper backups are for long-term retention, not failover.</span>" },
  { id:"D3-080", domain:3, obj:"3.5", diff:"easy", q:"An availability target of 99.999% uptime is commonly referred to as which term?", options:["Five nines","Two nines","Three nines","Four nines"], answer:0, explain:"<strong>Five nines</strong> refers to 99.999% uptime, about 5.26 minutes of downtime per year.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Two nines</b>: two nines is 99% uptime.</span><span class='qd'><b>Three nines</b>: three nines is 99.9% uptime.</span><span class='qd'><b>Four nines</b>: four nines is 99.99% uptime.</span>" },
  { id:"D3-081", domain:3, obj:"3.5", diff:"medium", q:"A two-node cluster uses a load balancer to distribute client requests across both servers, increasing performance as well as availability. Which cluster configuration is this?", options:["Active-active","Active-passive","Cold standby","Air-gapped"], answer:0, explain:"<strong>Active-active</strong> clusters use a load balancer to spread work across both nodes, providing availability and added performance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Active-passive</b>: in active-passive only one node is active and there is no load distribution.</span><span class='qd'><b>Cold standby</b>: a cold standby is offline until needed, not actively serving.</span><span class='qd'><b>Air-gapped</b>: air gap refers to network isolation, not cluster mode.</span>" },
  { id:"D3-082", domain:3, obj:"3.5", diff:"hard", q:"A sysadmin combines two physical NICs into a single virtual NIC with one IP address to provide both redundancy and aggregated bandwidth. What is this called?", options:["Failback","Synthetic full backup","Air gapping","NIC teaming"], answer:3, explain:"<strong>NIC teaming</strong> combines multiple NICs into a single virtual NIC, providing failover and link aggregation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Failback</b>: failback is the return of services to the original active node after recovery.</span><span class='qd'><b>Synthetic full backup</b>: that is a backup assembly technique.</span><span class='qd'><b>Air gapping</b>: air gapping isolates networks, it does not aggregate NICs.</span>" },
  { id:"D3-083", domain:3, obj:"3.5", diff:"medium", q:"An organization needs an alternate site that is fully equipped and continuously replicated so it can take over operations at a moment's notice. Which site type fits, despite the high cost?", options:["Warm site","Cold site","Air-gapped site","Hot site"], answer:3, explain:"<strong>Hot site</strong> is a fully equipped mirror with regular data replication, enabling immediate takeover at high cost.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Warm site</b>: a warm site has some equipment but needs setup and data migration before takeover.</span><span class='qd'><b>Cold site</b>: a cold site is just space and utilities, requiring the most time to activate.</span><span class='qd'><b>Air-gapped site</b>: an air gap is a network isolation concept, not a recovery site type.</span>" },
  { id:"D3-084", domain:3, obj:"3.5", diff:"easy", q:"A budget-conscious company chooses a recovery site that provides only office space, power, and HVAC, with no servers or workstations pre-installed. Which site type is this?", options:["Hot site","Cold site","Warm site","Cloud hot site"], answer:1, explain:"<strong>Cold site</strong> provides space, power, and HVAC but no equipment, making it the least expensive and slowest to activate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hot site</b>: a hot site has all equipment ready for immediate use.</span><span class='qd'><b>Warm site</b>: a warm site includes some hardware, more than a cold site.</span><span class='qd'><b>Cloud hot site</b>: that implies a ready cloud environment, not a bare cold site.</span>" },
  { id:"D3-085", domain:3, obj:"3.5", diff:"hard", q:"With one replication method, the client is told a transaction succeeded only after both the primary and secondary servers have written the data. Which replication type is this?", options:["Asynchronous replication","Periodic replication","File-level backup","Synchronous replication"], answer:3, explain:"<strong>Synchronous replication</strong> confirms success only after both servers hold the data, preventing loss if the primary fails.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Asynchronous replication</b>: asynchronous confirms after only the primary writes, risking loss before the secondary is updated.</span><span class='qd'><b>Periodic replication</b>: periodic replicates on a schedule, not based on per-transaction confirmation.</span><span class='qd'><b>File-level backup</b>: that is a backup type, not a replication confirmation model.</span>" },
  { id:"D3-086", domain:3, obj:"3.5", diff:"medium", q:"A sysadmin wants to validate that backups are actually recoverable without disturbing the production server. Which approach is recommended?", options:["Delete the production data to force a real restore","Restore the backup to a VM or alternate location and verify the data","Skip testing since backups always work","Overwrite the production server during business hours"], answer:1, explain:"<strong>Restore the backup to a VM or alternate location and verify the data</strong> proves recoverability without affecting production.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Delete the production data to force a real restore</b>: deliberately destroying production data is reckless.</span><span class='qd'><b>Skip testing since backups always work</b>: untested backups frequently fail when needed.</span><span class='qd'><b>Overwrite the production server during business hours</b>: that disrupts users and risks data.</span>" },
  { id:"D3-087", domain:3, obj:"3.5", diff:"medium", q:"A DRP must define how much data loss is acceptable and how quickly systems must be restored. Which two targets capture these goals?", options:["FIFO and GFS","RPO and RTO","NTFS and Share","DMZ and VLAN"], answer:1, explain:"<strong>RPO and RTO</strong> define the acceptable data loss (recovery point objective) and acceptable downtime (recovery time objective).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>FIFO and GFS</b>: those are backup media rotation schemes.</span><span class='qd'><b>NTFS and Share</b>: those are permission types, not recovery targets.</span><span class='qd'><b>DMZ and VLAN</b>: those are network segmentation concepts.</span>" },
  { id:"D3-088", domain:3, obj:"3.5", diff:"hard", q:"During DR testing, an organization runs the recovery procedures in a non-production environment using VMs while production stays online and unaffected. Which test type is this?", options:["Live failover (cutover)","Parallel recovery test","Paper test","Walk-through"], answer:1, explain:"<strong>Parallel recovery test</strong> runs DR procedures in a non-production environment, often with VMs, leaving production unaffected.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Live failover (cutover)</b>: a live failover tests on the actual production environment.</span><span class='qd'><b>Paper test</b>: a paper test only reviews procedures on paper with no execution.</span><span class='qd'><b>Walk-through</b>: a walk-through steps through procedures without restoring data.</span>" },
  { id:"D3-089", domain:3, obj:"3.5", diff:"medium", q:"A weekday backup catches all files changed since the previous full backup and does not reset the archive bit, so restores require only the full and the latest job. Which backup type is described?", options:["Incremental","Snapshot","Differential","Synthetic full"], answer:2, explain:"<strong>Differential</strong> backs up changes since the full without resetting the archive bit, so a restore needs only two jobs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Incremental</b>: an incremental resets the archive bit and requires every job since the full to restore.</span><span class='qd'><b>Snapshot</b>: a snapshot is a point-in-time read-only copy.</span><span class='qd'><b>Synthetic full</b>: a synthetic full aggregates a full plus incrementals into one job.</span>" },
  { id:"D3-090", domain:3, obj:"3.5", diff:"easy", q:"During DR testing, stakeholders sit together and discuss the recovery procedures, offering suggestions, without restoring any data. Which test type is this?", options:["Live failover","Parallel recovery","Paper test","Cutover"], answer:2, explain:"<strong>Paper test</strong> has stakeholders examine and discuss the procedures, considering suggestions without execution.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Live failover</b>: a live failover actually fails services over in production.</span><span class='qd'><b>Parallel recovery</b>: parallel recovery executes procedures in a non-production environment.</span><span class='qd'><b>Cutover</b>: cutover is another term for live failover on production.</span>" },
  { id:"D3-091", domain:3, obj:"3.6", diff:"easy", q:"A company is retiring HDDs from decommissioned servers and wants the most reliable method to ensure stored data cannot be recovered. Which approach is most reliable?", options:["Reformatting the drives","Deleting all files","Marking files as available for overwrite","Physical destruction such as shredding or incineration"], answer:3, explain:"<strong>Physical destruction such as shredding or incineration</strong> is highly reliable because the drive is physically destroyed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reformatting the drives</b>: reformatting is not particularly effective and data can be recovered.</span><span class='qd'><b>Deleting all files</b>: deleting only marks space as available; the data remains recoverable.</span><span class='qd'><b>Marking files as available for overwrite</b>: that is essentially deletion and leaves data recoverable.</span>" },
  { id:"D3-092", domain:3, obj:"3.6", diff:"medium", q:"A sysadmin needs to sanitize magnetic hard drives by using a strong magnetic field to destroy the stored data. Which method is this?", options:["Drilling","Reformatting","Encrypting","Degaussing"], answer:3, explain:"<strong>Degaussing</strong> magnetically destroys the stored data on magnetic media and is highly reliable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Drilling</b>: drilling physically damages the drive but is only somewhat reliable, and is not magnetic.</span><span class='qd'><b>Reformatting</b>: reformatting is a logical wipe that can leave recoverable data.</span><span class='qd'><b>Encrypting</b>: encryption protects active data but is not a media destruction method.</span>" },
  { id:"D3-093", domain:3, obj:"3.6", diff:"hard", q:"An organization follows NIST SP 800-88 guidance. To prevent data recovery even with laboratory forensic tools, which sanitization category should be applied to media being released outside the organization with the highest assurance?", options:["Clear","A simple file delete","Destroy","A quick format"], answer:2, explain:"<strong>Destroy</strong> provides the highest assurance under NIST SP 800-88, rendering media unusable so data cannot be recovered even with lab tools.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Clear</b>: clear protects against simple recovery but is a lower assurance level than destroy.</span><span class='qd'><b>A simple file delete</b>: deletion only marks space free and leaves data recoverable.</span><span class='qd'><b>A quick format</b>: a quick format is a logical wipe that leaves data recoverable.</span>" },
  { id:"D3-094", domain:3, obj:"3.6", diff:"medium", q:"As part of decommissioning, a server is placed offline but kept intact for a defined trial period before final removal. What is the primary purpose of this trial period?", options:["To confirm no unexpected clients or services still depend on the server","To improve the server's performance","To encrypt the server's drives","To degauss the server's media"], answer:0, explain:"<strong>To confirm no unexpected clients or services still depend on the server</strong>, the offline trial period catches overlooked dependencies before removal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To improve the server's performance</b>: the server is being retired, not optimized.</span><span class='qd'><b>To encrypt the server's drives</b>: encryption is not the goal of the offline period.</span><span class='qd'><b>To degauss the server's media</b>: media sanitization happens at destruction, not during the dependency-check period.</span>" },
  { id:"D3-095", domain:3, obj:"3.6", diff:"easy", q:"After decommissioning several servers, an administrator updates AD, SCCM, and centralized logging to remove the retired systems. Why is updating documentation and management systems important?", options:["To increase the server room humidity","To speed up the remaining servers' CPUs","To open additional firewall ports","To prevent continual false alerts and keep inventory accurate"], answer:3, explain:"<strong>To prevent continual false alerts and keep inventory accurate</strong>, since stale entries generate noise and confusion about missing systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To increase the server room humidity</b>: documentation has no effect on humidity.</span><span class='qd'><b>To speed up the remaining servers' CPUs</b>: updating records does not change CPU performance.</span><span class='qd'><b>To open additional firewall ports</b>: documentation updates are unrelated to firewall rules.</span>" },
  { id:"D3-096", domain:3, obj:"3.6", diff:"medium", q:"During decommissioning, drives must be transported to an off-site destruction facility. What is an essential precaution during this transport?", options:["Leave the drives unlabeled in a public dumpster","Power on the drives in the vehicle","Reconnect the drives to the production network","Secure the drives during transport to prevent data exposure"], answer:3, explain:"<strong>Secure the drives during transport to prevent data exposure</strong>, since unsecured drives in transit remain a confidentiality risk until destroyed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Leave the drives unlabeled in a public dumpster</b>: that exposes data to dumpster diving.</span><span class='qd'><b>Power on the drives in the vehicle</b>: powering them up does not secure them and is pointless.</span><span class='qd'><b>Reconnect the drives to the production network</b>: reconnecting decommissioned drives reintroduces risk.</span>" },
  { id:"D3-097", domain:3, obj:"3.6", diff:"hard", q:"An attacker retrieves discarded computer hardware from a company's trash and searches the drives for leftover data. What is this attack called, and what decommissioning practice prevents it?", options:["Dumpster diving, prevented by proper media sanitization and destruction","Eavesdropping, prevented by NIC teaming","Phishing, prevented by a guest network","Ramming, prevented by bollards"], answer:0, explain:"<strong>Dumpster diving, prevented by proper media sanitization and destruction</strong>, because destroying data before disposal removes the recoverable content.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Eavesdropping, prevented by NIC teaming</b>: eavesdropping intercepts traffic and NIC teaming does not stop it.</span><span class='qd'><b>Phishing, prevented by a guest network</b>: phishing tricks users; a guest network does not prevent it.</span><span class='qd'><b>Ramming, prevented by bollards</b>: ramming is a physical vehicle attack, not retrieving discarded hardware.</span>" },
  { id:"D3-098", domain:3, obj:"3.6", diff:"medium", q:"During decommissioning, an administrator finds abandoned network cable left by a previous tenant. Why should this cable be remediated (removed)?", options:["It increases the room's humidity","It causes confusion and creates reliability, security, and performance issues","It encrypts production traffic","It improves cluster failover times"], answer:1, explain:"<strong>It causes confusion and creates reliability, security, and performance issues</strong>, so abandoned cabling should be removed and recycled.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It increases the room's humidity</b>: cable does not affect humidity.</span><span class='qd'><b>It encrypts production traffic</b>: abandoned cable does nothing to encrypt traffic.</span><span class='qd'><b>It improves cluster failover times</b>: leftover cable does not benefit clustering.</span>" },
  { id:"D3-099", domain:3, obj:"3.6", diff:"easy", q:"A company recycles old servers and network cables instead of throwing them in a standard dumpster. What is a key reason proper electronics recycling is required?", options:["Recycling encrypts the data on the drives","Dumpsters automatically sanitize drives","Electronics contain toxic substances and valuable recoverable materials","Recycling improves server uptime"], answer:2, explain:"<strong>Electronics contain toxic substances and valuable recoverable materials</strong>, and it is typically illegal to discard them in normal trash.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Recycling encrypts the data on the drives</b>: recycling does not encrypt data; sanitization handles data removal.</span><span class='qd'><b>Dumpsters automatically sanitize drives</b>: dumpsters do not sanitize anything and create dumpster-diving risk.</span><span class='qd'><b>Recycling improves server uptime</b>: disposing of retired hardware does not affect active server uptime.</span>" },
  { id:"D3-100", domain:3, obj:"3.6", diff:"hard", q:"After sanitizing the data, a sysadmin decides to repurpose a decommissioned but still functional server rather than destroy it. Which is an appropriate repurposing use?", options:["An Internet-facing production database with no patches","A box for testing disaster restoral procedures or OS updates","A storage location for unencrypted PII backups","A replacement for the building's bollards"], answer:1, explain:"<strong>A box for testing disaster restoral procedures or OS updates</strong> is an appropriate low-risk repurposing of older hardware.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An Internet-facing production database with no patches</b>: exposing unpatched hardware to the Internet for production data is unsafe.</span><span class='qd'><b>A storage location for unencrypted PII backups</b>: storing unencrypted PII on retired hardware is a security risk.</span><span class='qd'><b>A replacement for the building's bollards</b>: a server cannot serve as a physical vehicle barrier.</span>" }
);
